import { useMemo, useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "What is a Z-score?", a: "A Z-score is a standard score that tells how many standard deviations a value is above or below the mean. Positive Z-scores are above the mean, and negative Z-scores are below it." },
  { q: "How do you calculate a Z-score?", a: "Use Z = (X - mean) / standard deviation. Subtract the mean from the raw score, then divide by the standard deviation." },
  { q: "What does a Z-score of 2 mean?", a: "A Z-score of 2 means the value is two standard deviations above the mean. In a normal distribution, that is around the 97.7th percentile." },
  { q: "How do you convert a Z-score to a percentile?", a: "Convert a Z-score to percentile using the standard normal cumulative distribution. The percentile is the area under the normal curve to the left of that Z-score." },
  { q: "What is the difference between Z-score and T-score?", a: "A Z-score uses a standard normal scale with mean 0 and standard deviation 1. A T-score is often transformed to have mean 50 and standard deviation 10, commonly used in tests and assessments." },
];

type Mode = "z" | "raw";
const fmt = (value: number) => Number.isFinite(value) ? Number(value.toFixed(4)).toLocaleString() : "Invalid";

function erf(x: number) {
  const sign = x >= 0 ? 1 : -1;
  const a1 = 0.254829592, a2 = -0.284496736, a3 = 1.421413741, a4 = -1.453152027, a5 = 1.061405429, p = 0.3275911;
  const ax = Math.abs(x);
  const t = 1 / (1 + p * ax);
  const y = 1 - (((((a5 * t + a4) * t) + a3) * t + a2) * t + a1) * t * Math.exp(-ax * ax);
  return sign * y;
}

function normalCdf(z: number) {
  return 0.5 * (1 + erf(z / Math.SQRT2));
}

export default function ZScoreCalculator() {
  const [mode, setMode] = useState<Mode>("z");
  const [raw, setRaw] = useState(85);
  const [mean, setMean] = useState(75);
  const [sd, setSd] = useState(10);
  const [zInput, setZInput] = useState(1);
  const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

  const result = useMemo(() => {
    if (sd <= 0) return { label: "Invalid input", value: "Standard deviation must be positive.", percentile: "", probability: "", step: "Standard deviation cannot be zero or negative." };
    if (mode === "z") {
      const z = (raw - mean) / sd;
      const percentile = normalCdf(z);
      return { label: "Z-Score", value: fmt(z), percentile: `${fmt(percentile * 100)}th percentile`, probability: `P(Z <= ${fmt(z)}) = ${fmt(percentile)}`, step: `Z = (X - ) /  = (${raw} - ${mean}) / ${sd} = ${fmt(z)}.` };
    }
    const value = mean + zInput * sd;
    const percentile = normalCdf(zInput);
    return { label: "Raw Score", value: fmt(value), percentile: `${fmt(percentile * 100)}th percentile`, probability: `P(Z <= ${fmt(zInput)}) = ${fmt(percentile)}`, step: `X =  + Z = ${mean} + (${zInput} x ${sd}) = ${fmt(value)}.` };
  }, [mode, raw, mean, sd, zInput]);

  return (
    <>
      <SEOHead title="Free Z-Score Calculator Online - Calculate Standard Score and Percentile Instantly | CalcHive" description="Free online Z-score calculator. Calculate Z-score from raw score mean and standard deviation or find raw score from Z-score with percentile rank instantly. 100% free, no signup required." canonical="/z-score-calculator" keywords="free z score calculator, z score calculator online free, standard score calculator free, calculate z score free, percentile from z score calculator free" category="Statistics Calculators" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-amber-600 dark:text-amber-400 bg-amber-50 dark:bg-amber-950/50 px-3 py-1 rounded-full mb-4 inline-block">Math</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Z-Score Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Use this free z score calculator to calculate z score free, find a raw score, and estimate percentile rank.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">
            <div><label htmlFor="mode" className="text-sm font-semibold text-foreground block mb-2">Mode</label><select id="mode" value={mode} onChange={(event) => setMode(event.target.value as Mode)} className={inputClass}><option value="z">Calculate Z-score</option><option value="raw">Calculate raw score</option></select></div>
            {mode === "z" ? <div><label htmlFor="raw" className="text-sm font-semibold text-foreground block mb-2">Raw score X</label><input id="raw" type="number" inputMode="decimal" value={raw} onChange={(event) => setRaw(Number(event.target.value))} className={inputClass} /></div> : <div><label htmlFor="z-input" className="text-sm font-semibold text-foreground block mb-2">Z-score</label><input id="z-input" type="number" inputMode="decimal" step="0.01" value={zInput} onChange={(event) => setZInput(Number(event.target.value))} className={inputClass} /></div>}
            <div><label htmlFor="mean" className="text-sm font-semibold text-foreground block mb-2">Mean </label><input id="mean" type="number" inputMode="decimal" value={mean} onChange={(event) => setMean(Number(event.target.value))} className={inputClass} /></div>
            <div><label htmlFor="sd" className="text-sm font-semibold text-foreground block mb-2">Standard deviation </label><input id="sd" type="number" inputMode="decimal" value={sd} onChange={(event) => setSd(Number(event.target.value))} className={inputClass} /></div>
          </div>
          <motion.div key={`${mode}-${raw}-${mean}-${sd}-${zInput}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-amber-500 to-amber-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">{result.label}</p><p className="text-5xl font-black text-white tracking-tight" data-testid="result-z-score">{result.value}</p>{result.percentile && <p className="text-white/70 text-sm mt-1">{result.percentile}</p>}</div>
            <div className="mt-4 bg-accent/60 border border-border rounded-xl p-4"><p className="text-xs font-bold uppercase tracking-wide text-muted-foreground mb-2">Step by step</p><p className="text-sm text-foreground" data-testid="result-steps">{result.step} {result.probability}</p></div>
          </motion.div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Z-Score for Any Data Point for Free</h2><p className="text-muted-foreground leading-relaxed">Enter a raw score, mean, and standard deviation. This standard score calculator free tool applies Z = (X - ) /  instantly.</p>
          <h2 className="text-2xl font-bold text-foreground">How to Find Percentile Rank From Z-Score</h2><p className="text-muted-foreground leading-relaxed">The percentile from z score calculator free estimate uses the standard normal curve to show the probability below your Z-score.</p>
          <h2 className="text-2xl font-bold text-foreground">Free Standard Score Calculator for Statistics Students</h2><p className="text-muted-foreground leading-relaxed">Use this z score calculator online free for statistics homework, test scores, normal distributions, and probability checks.</p>
        </section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/z-score-calculator" headingLevel="h3" />
      </main>
    </>
  );
}



